(inputs) => {
    const infrastructureAreaSqMeters = parseFloat(inputs.infrastructureAreaSqMeters);
    const damagePercentage = parseFloat(inputs.damagePercentage);
    const baseCostPerSqMeterUSD = parseFloat(inputs.baseCostPerSqMeterUSD);
    const materialCostIndex = parseFloat(inputs.materialCostIndex);
    const laborCostIndex = parseFloat(inputs.laborCostIndex);
    const logisticalComplexityFactor = parseFloat(inputs.logisticalComplexityFactor);
    const securityRiskPremium = parseFloat(inputs.securityRiskPremium);
    const projectManagementOverheadPercentage = parseFloat(inputs.projectManagementOverheadPercentage);
    const contingencyReservePercentage = parseFloat(inputs.contingencyReservePercentage);

    // Input validation and edge case handling for invalid or non-positive critical inputs
    if (isNaN(infrastructureAreaSqMeters) || infrastructureAreaSqMeters < 0 ||
        isNaN(damagePercentage) || damagePercentage < 0 || damagePercentage > 100 ||
        isNaN(baseCostPerSqMeterUSD) || baseCostPerSqMeterUSD < 0 ||
        isNaN(materialCostIndex) || materialCostIndex < 0 ||
        isNaN(laborCostIndex) || laborCostIndex < 0 ||
        isNaN(logisticalComplexityFactor) || logisticalComplexityFactor < 1 ||
        isNaN(securityRiskPremium) || securityRiskPremium < 0 ||
        isNaN(projectManagementOverheadPercentage) || projectManagementOverheadPercentage < 0 ||
        isNaN(contingencyReservePercentage) || contingencyReservePercentage < 0
    ) {
        return {
            estimatedBaseReconstructionCost: 0,
            totalMaterialCostComponent: 0,
            totalLaborCostComponent: 0,
            logisticsAndSecurityCost: 0,
            projectManagementCost: 0,
            contingencyCost: 0,
            grandTotalReconstructionCost: 0
        };
    }

    // If damage or area or base cost is zero, total reconstruction cost is zero.
    if (infrastructureAreaSqMeters === 0 || damagePercentage === 0 || baseCostPerSqMeterUSD === 0) {
        return {
            estimatedBaseReconstructionCost: 0,
            totalMaterialCostComponent: 0,
            totalLaborCostComponent: 0,
            logisticsAndSecurityCost: 0,
            projectManagementCost: 0,
            contingencyCost: 0,
            grandTotalReconstructionCost: 0
        };
    }

    // 1. Calculate the initial base cost for reconstruction based on area and damage.
    const estimatedBaseReconstructionCost = infrastructureAreaSqMeters * baseCostPerSqMeterUSD * (damagePercentage / 100);

    // 2. Calculate material and labor components, adjusted by local cost indices.
    const totalMaterialCostComponent = estimatedBaseReconstructionCost * materialCostIndex;
    const totalLaborCostComponent = estimatedBaseReconstructionCost * laborCostIndex;

    // 3. Calculate logistics and security costs.
    // Logistical complexity adds an incremental cost based on the base cost.
    // Security risk adds a direct percentage premium on the base cost.
    const logisticsExtraCost = estimatedBaseReconstructionCost * (logisticalComplexityFactor - 1);
    const securityPremiumCost = estimatedBaseReconstructionCost * (securityRiskPremium / 100);
    const logisticsAndSecurityCost = logisticsExtraCost + securityPremiumCost;

    // 4. Calculate subtotal before project management and contingency.
    const subtotalPreOverhead = totalMaterialCostComponent + totalLaborCostComponent + logisticsAndSecurityCost;

    // 5. Calculate Project Management & Overhead.
    const projectManagementCost = subtotalPreOverhead * (projectManagementOverheadPercentage / 100);

    // 6. Calculate subtotal before contingency.
    const subtotalPreContingency = subtotalPreOverhead + projectManagementCost;

    // 7. Calculate Contingency Reserve.
    const contingencyCost = subtotalPreContingency * (contingencyReservePercentage / 100);

    // 8. Calculate Grand Total.
    const grandTotalReconstructionCost = subtotalPreContingency + contingencyCost;

    return {
        estimatedBaseReconstructionCost,
        totalMaterialCostComponent,
        totalLaborCostComponent,
        logisticsAndSecurityCost,
        projectManagementCost,
        contingencyCost,
        grandTotalReconstructionCost
    };
}
